<span class="line"><span style="color:#A6ACCD;">$designWidth</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">1920</span><span style="color:#89DDFF;">;</span></span>
